package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.RszConstant;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.ListMultimap;
import lombok.Data;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.SortedSet;
import java.util.TreeSet;

public class CachedRszConstantService implements CachedService, RszConstantService {

    @Autowired
    private RszConstantService rszConstantService;

    private static final ThreadLocal<CachedRszConstantBuffer> BUFFER = new ThreadLocal<>();

    public CachedRszConstantService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public List<RszConstant> findByWerkgeversCategorieWerknemersKengetalBijdragen(
            WerkgeversCategorie werkgeversCategorie,
            List<DmfapplWnkengetal> werknemersKengetalBijdragen, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedRszConstantService.findByWerkgeversCategorieWerknemersKengetalBijdragen");
        CachedRszConstantBuffer buffer = CachedRszConstantService.getBuffer();
        RszConstantPlusKey key = new RszConstantPlusKey(werkgeversCategorie, werknemersKengetalBijdragen, datum);
        List<RszConstant> result;
        if (!buffer.containsKeyPlus(key)) {
            result = rszConstantService.findByWerkgeversCategorieWerknemersKengetalBijdragen(werkgeversCategorie, werknemersKengetalBijdragen, datum);
            buffer.putAllPlus(key, result);
        } else {
            result = buffer.getPlus(key);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public RszConstant getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetalBijdrage, Integer type, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedRszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum");
        CachedRszConstantBuffer buffer = CachedRszConstantService.getBuffer();
        RszConstantKey key = new RszConstantKey(werkgeversCategorie, werknemersKengetalBijdrage, type);
        List<RszConstant> lijst = buffer.get1(key);
        if (lijst == null) {
            lijst = rszConstantService.findByWerkgeversCategorieEnWerknemersKengetalBijdrage(werkgeversCategorie, werknemersKengetalBijdrage, type);
            buffer.put1(key, lijst);
        }

        RszConstant result = zoekLijst(lijst, datum);
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    private RszConstant zoekLijst(List<RszConstant> lijst, LocalDate datum) {
        RszConstant result = null;
        for (RszConstant rszConstant : lijst) {
            LocalDateInterval periode = new LocalDateInterval(rszConstant.getBeginDatum(), rszConstant.getEindDatum());
            if (periode.contains(datum)) {
                result = rszConstant;
                break;
            }
        }
        return result;
    }

    @Override
    public RszConstant getByWerkgeversCategorieEnWerknemersKengetalEnDatum(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetalBijdrage, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedRszConstantService.getByWerkgeversCategorieEnWerknemersKengetalEnDatum");
        RszConstant result = getByWerkgeversCategorieEnWerknemersKengetalEnDatumCached(werkgeversCategorie, werknemersKengetalBijdrage, datum);
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    private RszConstant getByWerkgeversCategorieEnWerknemersKengetalEnDatumCached(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetalBijdrage, LocalDate datum) {
        CachedRszConstantBuffer buffer = CachedRszConstantService.getBuffer();
        RszConstantKey key = new RszConstantKey(werkgeversCategorie, werknemersKengetalBijdrage, 0);
        List<RszConstant> lijst;
        if (!buffer.containsKey2(key)) {
            lijst = rszConstantService.findRszConstants(werkgeversCategorie, werknemersKengetalBijdrage);
            buffer.putAll2(key, lijst);
        } else {
            lijst = buffer.get2(key);
        }
        return zoekLijst(lijst, datum);
    }

    @Override
    public void clearCache() {
        CachedRszConstantService.getBuffer().clear();
    }

    private static class CachedRszConstantBuffer {

        private final Map<RszConstantKey, List<RszConstant>> rszConstantBuffer = new HashMap<>();
        private final ListMultimap<RszConstantPlusKey, RszConstant> rszConstantPlusBuffer = ArrayListMultimap.create();
        private final ListMultimap<RszConstantKey, RszConstant> rszConstantBuffer2 = ArrayListMultimap.create();

        public List<RszConstant> get1(RszConstantKey key) {
            return rszConstantBuffer.get(key);
        }

        public void put1(RszConstantKey key, List<RszConstant> lijst) {
            rszConstantBuffer.put(key, lijst);
        }

        public List<RszConstant> getPlus(RszConstantPlusKey key) {
            return rszConstantPlusBuffer.get(key);
        }

        public void putPlus(RszConstantPlusKey key, RszConstant rszConstant) {
            rszConstantPlusBuffer.put(key, rszConstant);
        }

        public void putAllPlus(RszConstantPlusKey key, List<RszConstant> lijst) {
            rszConstantPlusBuffer.putAll(key, lijst);
        }

        public boolean containsKeyPlus(RszConstantPlusKey key) {
            return rszConstantPlusBuffer.containsKey(key);
        }

        public List<RszConstant> get2(RszConstantKey key) {
            return rszConstantBuffer2.get(key);
        }

        public void putAll2(RszConstantKey key, List<RszConstant> lijst) {
            rszConstantBuffer2.putAll(key, lijst);
        }

        public boolean containsKey2(RszConstantKey key) {
            return rszConstantBuffer2.containsKey(key);
        }

        public void clear() {
            rszConstantBuffer.clear();
            rszConstantPlusBuffer.clear();
        }
    }

    private static CachedRszConstantBuffer getBuffer() {
        CachedRszConstantBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedRszConstantBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    private static class RszConstantKey {

        private final int werkgeversCategorie;
        private final int werknemersKengetalBijdrage;
        private final int type;

        RszConstantKey(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetalBijdrage, int type) {
            this.werkgeversCategorie = werkgeversCategorie.getCode();
            this.werknemersKengetalBijdrage = werknemersKengetalBijdrage.getCode();
            this.type = type;
        }
    }

    @Data
    private static class RszConstantPlusKey {

        private final int werkgeversCategorie;
        private final String werknemersKengetalBijdrageString;
        private final LocalDate datum;

        RszConstantPlusKey(WerkgeversCategorie werkgeversCategorie, List<DmfapplWnkengetal> werknemersKengetalBijdragen, LocalDate datum) {
            this.werkgeversCategorie = werkgeversCategorie.getCode();
            SortedSet<DmfapplWnkengetal> werknemersKengetalBijdrageSet = new TreeSet<>(werknemersKengetalBijdragen);
            StringBuilder builder = new StringBuilder();
            for (DmfapplWnkengetal werknemersKengetalBijdrage : werknemersKengetalBijdrageSet) {
                builder.append(werknemersKengetalBijdrage.getCode()).append('-');
            }
            this.werknemersKengetalBijdrageString = builder.toString();
            this.datum = datum;
        }
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<RszConstant> findByWerkgeversCategorieEnWerknemersKengetalBijdrage(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetalBijdrage, Integer type) {
        return rszConstantService.findByWerkgeversCategorieEnWerknemersKengetalBijdrage(werkgeversCategorie, werknemersKengetalBijdrage, type);
    }

    @Override
    public List<RszConstant> findByWerkgeversCategorieEnWerknemersKengetalBijdrage(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetalBijdrage) {
        return rszConstantService.findByWerkgeversCategorieEnWerknemersKengetalBijdrage(werkgeversCategorie, werknemersKengetalBijdrage);
    }

    @Override
    public List<RszConstant> findByWerkgeversCategorie(WerkgeversCategorie werkgeversCategorie, LocalDate datum) {
        return rszConstantService.findByWerkgeversCategorie(werkgeversCategorie, datum);
    }

    @Override
    public List<RszConstant> findRszConstants(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetalBijdrage) {
        return rszConstantService.findRszConstants(werkgeversCategorie, werknemersKengetalBijdrage);
    }

    @Override
    public List<RszConstant> findRszConstanten(List<WerkgeversCategorie> werkgeversCategorieen, DmfapplWnkengetal werknemersKengetalBijdrage) {
        return rszConstantService.findRszConstanten(werkgeversCategorieen, werknemersKengetalBijdrage);
    }

    @Override
    public List<RszConstant> findRszConstants(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetalBijdrage, LocalDate datum) {
        return rszConstantService.findRszConstants(werkgeversCategorie, werknemersKengetalBijdrage, datum);
    }

    @Override
    public RszConstant getById(Integer id) {
        return rszConstantService.getById(id);
    }

    @Override
    public RszConstant getById(Integer id, String fetchFields) {
        return rszConstantService.getById(id, fetchFields);
    }

    @Override
    public List<RszConstant> findAll() {
        return rszConstantService.findAll();
    }

    @Override
    public RszConstant create(RszConstant constant) {
        return rszConstantService.create(constant);
    }

    @Override
    public void update(RszConstant constant) {
        rszConstantService.update(constant);
    }

    @Override
    public void delete(RszConstant constant) {
        rszConstantService.delete(constant);
    }

    @Override
    public RszConstant getByCriteria(CriteriaBuilder cb) {
        return rszConstantService.getByCriteria(cb);
    }


    @Override
    public List<RszConstant> findAll(String fetchFields) {
        return rszConstantService.findAll(fetchFields);
    }

    @Override
    public List<RszConstant> findByCriteria(CriteriaBuilder cb) {
        return rszConstantService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return rszConstantService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, RszConstant> cacheByCriteria(CriteriaBuilder cb) {
        return rszConstantService.cacheByCriteria(cb);
    }

    @Override
    public RszConstant getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return rszConstantService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<RszConstant> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return rszConstantService.findByCriteriaTemporalFree(cb);
    }

}
